import React, { useState } from "react";
import axios from "axios";

const Login = () => {
  const [form, setForm] = useState({});

  const handle = (e) =>
    setForm({ ...form, [e.target.name]: e.target.value });

  const submit = async (e) => {
    e.preventDefault();

    const res = await axios.post(
      "http://localhost:5000/api/auth/login",
      form
    );

    localStorage.setItem("user", JSON.stringify(res.data.user));

    if (res.data.user.role === "customer") {
      window.location.href = "/customer";
    } else {
      window.location.href = "/labour";
    }
  };

  return (
    <div style={styles.container}>

      <form style={styles.card} onSubmit={submit}>

        <h2 style={styles.title}>Welcome Back</h2>

        <p style={styles.subtitle}>
          Login to continue to your dashboard
        </p>

        <input
          name="email"
          placeholder="Email"
          onChange={handle}
          style={styles.input}
        />

        <input
          name="password"
          placeholder="Password"
          type="password"
          onChange={handle}
          style={styles.input}
        />

        <button style={styles.btn}>
          Login
        </button>

      </form>

    </div>
  );
};

export default Login;

const styles = {
  container: {
    height: "100vh",
    background: "#0b1220",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    fontFamily: "Segoe UI"
  },

  card: {
    width: "350px",
    padding: "30px",
    borderRadius: "16px",
    background: "#111a2e",
    border: "1px solid #1f2a44",
    textAlign: "center"
  },

  title: {
    color: "white",
    marginBottom: "5px"
  },

  subtitle: {
    color: "#94a3b8",
    fontSize: "13px",
    marginBottom: "20px"
  },

  input: {
    width: "100%",
    padding: "10px",
    margin: "8px 0",
    borderRadius: "8px",
    border: "1px solid #1f2a44",
    background: "#0b1220",
    color: "white",
    outline: "none"
  },

  btn: {
    width: "100%",
    padding: "10px",
    marginTop: "10px",
    background: "#22c55e",
    border: "none",
    color: "white",
    borderRadius: "8px",
    cursor: "pointer"
  }
};
